          options: [
            { id: 'A', text: 'return "error"', explanation: 'Returning a string is not proper error handling — the caller might ignore it.' },
            { id: 'B', text: 'raise ValueError(f"age cannot be negative: {age}")', explanation: 'Correct! raise explicitly raises an exception. ValueError is appropriate for "invalid value" situations.' },
            { id: 'C', text: 'print("age cannot be negative")', explanation: 'print only outputs — the program continues running and does not prevent the invalid value from being used.' },
            { id: 'D', text: 'exit(1)', explanation: 'exit() terminates the entire program. You should let the caller decide how to handle the error.' },
          ],
          correctAnswer: 'B',
          hints: ['raise lets the function pass the error to the caller for handling, rather than handling it itself'],
          explanation: 'raise explicitly raises an exception, letting the caller handle it with try/except. This is clearer and harder to ignore than returning error codes or using print.',
          frameworkTip: 'Function design principle: validate input → invalid inputs get raise → let the caller try/except.',
