          question: 'Write a function search_products(conn, filters) that takes a SQLite connection and a filter dict (possible keys: category, min_price, max_price). Dynamically build the WHERE clause and return results.\nExample: filters={"category": "Electronics", "min_price": 100} should generate WHERE category = ? AND price >= ?\nAll conditions are optional (filters may be an empty dict). Return list of dicts.',
          starterCode: 'import sqlite3\n\ndef search_products(conn, filters):\n    # Dynamically build SQL WHERE clause\n    # Use parameterized queries (? placeholders)\n    # Return list of dicts\n    pass',
          expectedQuery: 'import sqlite3\n\ndef search_products(conn, filters):\n    query = "SELECT * FROM products"\n    conditions = []\n    params = []\n    if "category" in filters:\n        conditions.append("category = ?")\n        params.append(filters["category"])\n    if "min_price" in filters:\n        conditions.append("price >= ?")\n        params.append(filters["min_price"])\n    if "max_price" in filters:\n        conditions.append("price <= ?")\n        params.append(filters["max_price"])\n    if conditions:\n        query += " WHERE " + " AND ".join(conditions)\n    conn.row_factory = sqlite3.Row\n    rows = conn.execute(query, params).fetchall()\n    return [dict(row) for row in rows]',
          testCases: [
            { input: 'import sqlite3; conn = sqlite3.connect(":memory:"); conn.execute("CREATE TABLE products (id INTEGER PRIMARY KEY, name TEXT, category TEXT, price REAL)"); conn.executemany("INSERT INTO products VALUES (?,?,?,?)", [(1,"Laptop","Electronics",1200),(2,"Phone","Electronics",800),(3,"Shirt","Clothing",50)]); conn.commit(); search_products(conn, {"category": "Electronics"})' },
            { input: 'import sqlite3; conn = sqlite3.connect(":memory:"); conn.execute("CREATE TABLE products (id INTEGER PRIMARY KEY, name TEXT, category TEXT, price REAL)"); conn.executemany("INSERT INTO products VALUES (?,?,?,?)", [(1,"Laptop","Electronics",1200),(2,"Phone","Electronics",800),(3,"Shirt","Clothing",50)]); conn.commit(); search_products(conn, {"min_price": 100, "max_price": 1000})' },
            { input: 'import sqlite3; conn = sqlite3.connect(":memory:"); conn.execute("CREATE TABLE products (id INTEGER PRIMARY KEY, name TEXT, category TEXT, price REAL)"); conn.executemany("INSERT INTO products VALUES (?,?,?,?)", [(1,"Laptop","Electronics",1200),(2,"Phone","Electronics",800),(3,"Shirt","Clothing",50)]); conn.commit(); search_products(conn, {})' },
          ],
