export const pythonWorldsEn = _pythonWorldsEn.map(world => {
  const extras = extrasByWorld[world.id]
  if (!extras) return world
  return mergeExtras({ ...world, quests: world.quests.map(q => ({ ...q, challenges: [...q.challenges] })) }, extras)
})
